import { Engine, Scene, ArcRotateCamera, Vector3, Color4 } from '@babylonjs/core';
import { TilesRenderer } from '3d-tiles-renderer/babylonjs';
import GUI from 'lil-gui';

const TILESET_URL = 'https://raw.githubusercontent.com/NASA-AMMOS/3DTilesSampleData/master/msl-dingo-gap/0528_0260184_to_s64o256_colorize/0528_0260184_to_s64o256_colorize/0528_0260184_to_s64o256_colorize_tileset.json';

// gui
const params = {
	enabled: true,
	visibleTiles: 0,
};

const gui = new GUI();
gui.add( params, 'enabled' );
gui.add( params, 'visibleTiles' ).listen().disable();

// init engine
const canvas = document.getElementById( 'renderCanvas' );
const engine = new Engine( canvas, true, { useLargeWorldRendering: true } );
engine.setHardwareScalingLevel( 1 / window.devicePixelRatio );

// scene
const scene = new Scene( engine );
scene.clearColor = new Color4( 0.05, 0.05, 0.05, 1 );
scene.useRightHandedSystem = true;

// Camera controls
const camera = new ArcRotateCamera(
	'camera',
	- Math.PI / 2,
	Math.PI / 2.5,
	50,
	new Vector3( 0, 0, 0 ),
	scene,
);
camera.attachControl( canvas, true );
camera.minZ = 0.1;
camera.maxZ = 1000;

// instantiate tiles renderer and orient the group so it's Z+ down
const tiles = new TilesRenderer( TILESET_URL, scene );
tiles.group.rotation.x = Math.PI / 2;

// render
scene.onBeforeRenderObservable.add( () => {

	if ( params.enabled ) {

		tiles.update();

	}

	params.visibleTiles = tiles.visibleTiles.size;

} );

engine.runRenderLoop( () => {

	scene.render();

} );

// resize
window.addEventListener( 'resize', () => {

	engine.resize();

} );

import { Scene, Engine, GeospatialCamera, Vector3, Color4 } from '@babylonjs/core';
import { GeospatialClippingBehavior } from '@babylonjs/core/Behaviors/Cameras';
import { TilesRenderer } from '3d-tiles-renderer/babylonjs';
import { CesiumIonAuthPlugin } from '3d-tiles-renderer/core/plugins';
import GUI from 'lil-gui';

const GOOGLE_TILES_ASSET_ID = 2275207;

const PLANET_RADIUS = 6378137;

// gui
const params = {
	enabled: true,
	visibleTiles: 0,
	errorTarget: 20,
	minZ: 0,
	maxZ: 0,
};

const gui = new GUI();
gui.add( params, 'enabled' );
gui.add( params, 'visibleTiles' ).name( 'Visible Tiles' ).listen().disable();
gui.add( params, 'errorTarget', 1, 100 );
gui.add( params, 'minZ' ).name( 'Camera MinZ' ).listen().disable();
gui.add( params, 'maxZ' ).name( 'Camera MaxZ' ).listen().disable();

// engine
const canvas = document.getElementById( 'renderCanvas' );
const engine = new Engine( canvas, true, { useLargeWorldRendering: true } );
engine.setHardwareScalingLevel( 1 / window.devicePixelRatio );

// scene
const scene = new Scene( engine );
scene.clearColor = new Color4( 0.05, 0.05, 0.05, 1 );

// 3D Tiles data uses right-handed coordinate system
scene.useRightHandedSystem = true;

// camera
const camera = new GeospatialCamera( 'geo', scene, { planetRadius: PLANET_RADIUS } );

camera.attachControl( true );
const clippingBehavior = new GeospatialClippingBehavior();
camera.addBehavior( clippingBehavior );

// Start farther out, then fly in once tiles are loaded
camera.radius = 50000;

// Set center to Tokyo Tower location (ECEF coordinates)
// Tokyo Tower: 35.6586° N, 139.7454° E
camera.center = new Vector3( - 3959611.825621192, 3352599.0363458656, 3697549.0362687325 );
camera.pitch = 1.167625429373872;
camera.yaw = - 0.2513281792775774;

camera.checkCollisions = true;
scene.collisionsEnabled = true;

// Fly to close view once tiles load
let hasZoomedIn = false;

// tiles
const tiles = new TilesRenderer( null, scene );
tiles.registerPlugin( new CesiumIonAuthPlugin( {
	apiToken: import.meta.env.VITE_ION_KEY,
	assetId: GOOGLE_TILES_ASSET_ID,
	autoRefreshToken: true,
} ) );
tiles.errorTarget = params.errorTarget;

// Babylon render loop

scene.onBeforeRenderObservable.add( () => {

	if ( params.enabled ) {

		tiles.errorTarget = params.errorTarget;
		tiles.update();
		params.visibleTiles = tiles.visibleTiles.size;
		params.minZ = camera.minZ;
		params.maxZ = camera.maxZ;


		// Once we have some tiles visible, fly in to target
		if ( ! hasZoomedIn && tiles.visibleTiles.size > 5 ) {

			hasZoomedIn = true;
			camera.flyToAsync( undefined, undefined, 300, undefined, 2000 );

		}

	}

	// update attributions
	const attributions = tiles.getAttributions();
	const creditsEl = document.getElementById( 'credits' );
	creditsEl.innerText = attributions[ 0 ]?.value || '';

} );

engine.runRenderLoop( () => {

	scene.render();

} );

// Handle window resize
window.addEventListener( 'resize', () => {

	engine.resize();

} );

// @title: WMTS Capabilities & Tiles
// @description: Load and display WMTS (Web Map Tile Service) layers with capabilities parsing
// @category: plugins
// @deps: three, 3d-tiles-renderer

import {
	Scene,
	WebGLRenderer,
	PerspectiveCamera,
} from 'three';
import { TilesRenderer, GlobeControls, EnvironmentControls } from '3d-tiles-renderer';
import { TilesFadePlugin, UpdateOnChangePlugin, WMTSCapabilitiesLoader, WMTSTilesPlugin } from '3d-tiles-renderer/plugins';
import { GUI } from 'three/examples/jsm/libs/lil-gui.module.min.js';

const url = window.location.hash.replace( /^#/, '' ) || 'https://gibs.earthdata.nasa.gov/wmts/epsg4326/best/wmts.cgi?SERVICE=WMTS&request=GetCapabilities';
const compatibleCRSList = [ 'EPSG:4326', 'EPSG:3857' ];

let controls, scene, renderer;
let tiles, camera, gui;
let params, capabilities;

init();
render();

function init() {

	// renderer
	renderer = new WebGLRenderer( { antialias: true } );
	renderer.setPixelRatio( window.devicePixelRatio );
	renderer.setSize( window.innerWidth, window.innerHeight );
	renderer.setClearColor( 0x111111 );
	renderer.setAnimationLoop( render );

	document.body.appendChild( renderer.domElement );

	// scene
	scene = new Scene();

	// set up cameras and ortho / perspective transition
	camera = new PerspectiveCamera( 60, window.innerWidth / window.innerHeight, 0.001, 10000 );

	// update the capabilities file
	updateCapabilities();

	// events
	onWindowResize();
	window.addEventListener( 'resize', onWindowResize, false );
	window.addEventListener( 'hashchange', () => location.reload() );

}

async function updateCapabilities() {

	// load the capabilities file
	capabilities = await new WMTSCapabilitiesLoader().loadAsync( url );

	// use a default overlay
	let defaultLayer = 'MODIS_Terra_CorrectedReflectance_TrueColor';

	if ( ! capabilities.layers.find( l => l.identifier === defaultLayer ) ) {

		defaultLayer = capabilities.layers.find( l =>
			l.tileMatrixSets.some( tms => compatibleCRSList.includes( tms.supportedCRS ) )
		).identifier;

	}

	// set up the parameters
	params = {
		layer: defaultLayer,
		style: null,
		tileMatrixSet: null,
		planar: false,
		dimensions: {},
	};

	rebuildGUI();
	rebuildTiles();

}

function rebuildGUI() {

	if ( gui ) {

		gui.destroy();

	}

	params.style = null;
	params.tileMatrixSet = null;
	params.dimensions = {};

	// initialize the layer settings
	const layer = capabilities.layers.find( l => l.identifier === params.layer );
	params.style = layer.styles.find( s => s.isDefault )?.identifier || layer.styles[ 0 ].identifier;
	const compatibleTileMatrixSet = layer.tileMatrixSets.find( tms => compatibleCRSList.includes( tms.supportedCRS ) );
	params.tileMatrixSet = compatibleTileMatrixSet ? compatibleTileMatrixSet.identifier : layer.tileMatrixSets[ 0 ].identifier;

	// update the ui
	const abstract = capabilities.serviceIdentification.abstract;
	document.getElementById( 'info' ).innerHTML =
		'<b>' + capabilities.serviceIdentification.title + '</b>' + ( abstract ? '<br/>' + abstract : '' ) +
		'<br/>' + layer.title;


	gui = new GUI();
	gui.add( params, 'planar' ).onChange( rebuildTiles );
	gui.add( params, 'layer', capabilities.layers.map( l => l.identifier ) ).onChange( () => {

		rebuildGUI( url );
		rebuildTiles();

	} );
	gui.add( params, 'tileMatrixSet', layer.tileMatrixSets.map( tms => tms.identifier ) ).onChange( rebuildTiles );
	gui.add( params, 'style', layer.styles.map( s => s.identifier ) ).onChange( rebuildTiles );

	// create the UI for dimensions
	for ( const key in layer.dimensions ) {

		const dim = layer.dimensions[ key ];
		params.dimensions[ dim.identifier ] = layer.dimensions[ key ].defaultValue;

		// Note that NASA GIBS uses a custom notation for time
		// https://www.earthdata.nasa.gov/news/blog/wmts-time-dimensions-restful-access
		let values = dim.values;
		if ( dim.identifier === 'Time' && /gibs.earthdata/.test( url ) ) {

			values = values.flatMap( v => {

				const tokens = v.split( /\//g );
				tokens.pop();
				return tokens;

			} );

			if ( /^MODIS_Terra/.test( params.layer ) ) {

				// NOTE: this is a good full-ranged time to use with a full set of data typically used by GIBs for demos
				values.push( '2013-06-16' );
				params.dimensions[ dim.identifier ] = '2013-06-16';

			}

		}

		gui.add( params.dimensions, dim.identifier, values ).onChange( rebuildTiles );

	}

}

function rebuildTiles() {

	if ( tiles ) {

		tiles.dispose();

	}

	if ( controls ) {

		controls.dispose();
		controls = null;

	}

	// tiles
	tiles = new TilesRenderer();
	tiles.registerPlugin( new TilesFadePlugin() );
	tiles.registerPlugin( new UpdateOnChangePlugin() );
	tiles.registerPlugin( new WMTSTilesPlugin( {
		shape: params.planar ? 'planar' : 'ellipsoid',
		center: true,
		capabilities,
		...params,
	} ) );

	tiles.setCamera( camera );
	scene.add( tiles.group );

	if ( params.planar ) {

		// create the controls
		controls = new EnvironmentControls( scene, camera, renderer.domElement );
		controls.enableDamping = true;
		controls.minDistance = 1e-4;
		controls.maxDistance = 5;
		controls.cameraRadius = 0;
		controls.fallbackPlane.normal.set( 0, 0, 1 );
		controls.up.set( 0, 0, 1 );
		controls.camera.position.set( 0, 0, 2 );
		controls.camera.quaternion.identity();

		// reset the camera
		camera.near = 1e-4;
		camera.far = 10;
		camera.updateProjectionMatrix();

	} else {

		// init tiles
		tiles.group.rotation.x = - Math.PI / 2;

		// create the controls
		controls = new GlobeControls( scene, camera, renderer.domElement );
		controls.setEllipsoid( tiles.ellipsoid, tiles.group );
		controls.enableDamping = true;
		controls.camera.position.set( 0, 0, 1.75 * 1e7 );
		controls.camera.quaternion.identity();
		controls.minDistance = 150;

	}

}

function onWindowResize() {

	const aspect = window.innerWidth / window.innerHeight;
	camera.aspect = aspect;
	camera.updateProjectionMatrix();

	renderer.setSize( window.innerWidth, window.innerHeight );

}

function render() {

	if ( controls ) {

		controls.update();
		camera.updateMatrixWorld();

	}

	if ( tiles ) {

		tiles.setCamera( camera );
		tiles.setResolutionFromRenderer( camera, renderer );
		tiles.update();

	}

	renderer.render( scene, camera );

}

import { Scene, WebGLRenderer, PerspectiveCamera } from 'three';
import { TilesRenderer, GlobeControls } from '3d-tiles-renderer';
import { TilesFadePlugin, UpdateOnChangePlugin, WMSCapabilitiesLoader, WMSTilesPlugin } from '3d-tiles-renderer/plugins';
import { GUI } from 'three/examples/jsm/libs/lil-gui.module.min.js';

const url =
	window.location.hash.replace( /^#/, '' ) ||
	'https://basemap.nationalmap.gov/arcgis/services/USGSHydroCached/MapServer/WMSServer?SERVICE=WMS';

if ( ! window.location.hash ) {

	document.getElementById( 'info' ).innerHTML = 'Hydrography data set courtesy of the <a href="https://basemap.nationalmap.gov/arcgis/rest/services">USGS National Map Service</a>.';

}

let controls, scene, renderer;
let tiles, camera, gui;
let params, capabilities;

init();

function init() {

	// renderer
	renderer = new WebGLRenderer( { antialias: true } );
	renderer.setPixelRatio( window.devicePixelRatio );
	renderer.setSize( window.innerWidth, window.innerHeight );
	renderer.setClearColor( 0x111111 );
	renderer.setAnimationLoop( render );
	document.body.appendChild( renderer.domElement );

	// set up
	scene = new Scene();
	camera = new PerspectiveCamera( 60, window.innerWidth / window.innerHeight );

	// load the tiles
	updateCapabilities();

	onWindowResize();
	window.addEventListener( 'resize', onWindowResize, false );
	window.addEventListener( 'hashchange', () => location.reload() );

}

async function updateCapabilities() {

	capabilities = await new WMSCapabilitiesLoader().loadAsync( url + '&request=GetCapabilities' );

	const defaultLayer = capabilities.layers[ 0 ];
	params = {
		layer: defaultLayer.name,
		styles: defaultLayer.styles[ 0 ]?.name || '',
		crs: 'EPSG:4326',
		format: 'image/png',
		tileDimension: 256,
	};

	rebuildGUI();
	rebuildTiles();

}

function rebuildGUI() {

	if ( gui ) {

		gui.destroy();

	}

	const layer = capabilities.layers.find( l => l.name === params.layer );

	gui = new GUI();
	gui.add( params, 'layer', capabilities.layers.map( l => l.name ) )
		.onChange( v => {

			const selectedLayer = capabilities.layers.find( l => l.name === v );
			params.crs = selectedLayer.crs[ 0 ];
			params.styles = selectedLayer.styles[ 0 ]?.name || '';
			rebuildGUI();
			rebuildTiles();

		} );
	gui.add( params, 'styles', layer.styles.map( s => s.name ) ).onChange( rebuildTiles );
	gui.add( params, 'crs', layer.crs ).onChange( rebuildTiles );
	gui.add( params, 'format', capabilities.request.GetMap.formats ).onChange( rebuildTiles );
	gui.add( params, 'tileDimension', [ 256, 512 ] ).onChange( rebuildTiles );

}

function rebuildTiles() {

	if ( tiles ) {

		tiles.dispose();
		tiles = null;

	}

	if ( controls ) {

		controls.dispose();
		controls = null;

	}

	const layer = capabilities.layers.find( l => l.name === params.layer );

	// WMS overlay layer
	tiles = new TilesRenderer();
	tiles.registerPlugin( new TilesFadePlugin() );
	tiles.registerPlugin( new UpdateOnChangePlugin() );
	tiles.registerPlugin(
		new WMSTilesPlugin( {
			shape: 'ellipsoid',
			url: capabilities.request.GetMap.href,
			layer: params.layer,
			contentBoundingBox: layer.contentBoundingBox,
			crs: params.crs,
			format: params.format,
			tileDimension: params.tileDimension,
			styles: params.styles,
			version: capabilities.version,
		} ),
	);

	tiles.group.rotation.x = - Math.PI / 2;
	scene.add( tiles.group );

	// init controls
	controls = new GlobeControls( scene, camera, renderer.domElement );
	controls.setEllipsoid( tiles.ellipsoid, tiles.group );
	controls.enableDamping = true;
	controls.camera.position.set( 0, 0, 1.75 * 1e7 );
	controls.camera.quaternion.identity();
	controls.minDistance = 150;

}

function onWindowResize() {

	const aspect = window.innerWidth / window.innerHeight;
	camera.aspect = aspect;
	camera.updateProjectionMatrix();
	renderer.setSize( window.innerWidth, window.innerHeight );

}

function render() {

	if ( controls ) {

		controls.update();
		camera.updateMatrixWorld();

	}

	if ( tiles ) {

		tiles.setCamera( camera );
		tiles.setResolutionFromRenderer( camera, renderer );
		tiles.update();

	}

	renderer.render( scene, camera );

}

import { TilesRenderer } from '3d-tiles-renderer';
import {
	Scene,
	DirectionalLight,
	AmbientLight,
	WebGLRenderer,
	PerspectiveCamera,
	Box3,
	Raycaster,
	Mesh,
	MeshBasicMaterial,
	Group,
	TorusGeometry,
	GridHelper,
	BufferGeometry,
	Float32BufferAttribute,
	LineBasicMaterial,
	AdditiveBlending,
	Line,
	Vector3,
	RingGeometry,
	Sphere,
} from 'three';
import { GUI } from 'three/examples/jsm/libs/lil-gui.module.min.js';
import { VRButton } from 'three/examples/jsm/webxr/VRButton.js';
import { XRControllerModelFactory } from 'three/examples/jsm/webxr/XRControllerModelFactory.js';

let camera, scene, renderer, tiles;
let workspace;
let box, sphere, grid;
let raycaster, fwdVector, intersectRing;
let offsetParent;
let controller, controllerGrip;
let xrSession = null;
const tasks = [];
const upVector = new Vector3( 0, 1, 0 );

const params = {

	'displayGrid': true,

};

init();

function init() {

	scene = new Scene();

	// primary camera view
	renderer = new WebGLRenderer( { antialias: true } );
	renderer.setPixelRatio( window.devicePixelRatio );
	renderer.setSize( window.innerWidth, window.innerHeight );
	renderer.setClearColor( 0xbbbbbb );
	renderer.xr.enabled = true;

	document.body.appendChild( renderer.domElement );
	renderer.domElement.tabIndex = 1;

	renderer.setAnimationLoop( animate );

	// create workspace
	workspace = new Group();
	scene.add( workspace );

	grid = new GridHelper( 10, 10, 0xffffff, 0xffffff );
	grid.material.transparent = true;
	grid.material.opacity = 0.5;
	grid.material.depthWrite = false;
	workspace.add( grid );

	camera = new PerspectiveCamera( 60, window.innerWidth / window.innerHeight, 0.1, 4000 );
	camera.position.set( 0, 1, 0 );
	workspace.add( camera );

	// lights
	const dirLight = new DirectionalLight( 0xffffff );
	dirLight.position.set( 1, 2, 3 );
	scene.add( dirLight );

	const ambLight = new AmbientLight( 0xffffff, 0.2 );
	scene.add( ambLight );

	// tileset
	box = new Box3();
	sphere = new Sphere();

	// parent for centering the tileset
	offsetParent = new Group();
	offsetParent.rotation.x = Math.PI / 2;
	offsetParent.position.y = 32;
	scene.add( offsetParent );

	tiles = new TilesRenderer( 'https://raw.githubusercontent.com/NASA-AMMOS/3DTilesSampleData/master/msl-dingo-gap/0528_0260184_to_s64o256_colorize/scene-tileset.json' );
	offsetParent.add( tiles.group );

	// We set camera for tileset
	tiles.setCamera( camera );
	tiles.setResolutionFromRenderer( camera, renderer );


	// We define a custom scheduling callback to handle also active WebXR sessions
	const tilesSchedulingCB = func => {

		tasks.push( func );

	};

	// We set our scheduling callback for tiles downloading and parsing
	tiles.downloadQueue.schedulingCallback = tilesSchedulingCB;
	tiles.parseQueue.schedulingCallback = tilesSchedulingCB;

	tiles.lruCache.maxSize = 1200;
	tiles.lruCache.minSize = 900;

	// Raycasting init
	raycaster = new Raycaster();
	fwdVector = new Vector3( 0, 0, 1 );

	const rayIntersectMat = new MeshBasicMaterial( { color: 0xb2dfdb } );
	intersectRing = new Mesh( new TorusGeometry( 1.5, 0.2, 16, 100 ), rayIntersectMat );
	intersectRing.visible = false;
	scene.add( intersectRing );

	// vr setup
	document.body.appendChild( VRButton.createButton( renderer ) );

	controller = renderer.xr.getController( 0 );
	controller.addEventListener( 'selectstart', () => {

		if ( intersectRing.visible ) {

			workspace.position.copy( intersectRing.position );

		}

	} );
	controller.addEventListener( 'connected', function ( event ) {

		this.controllerActive = true;
		this.add( buildController( event.data ) );

	} );
	controller.addEventListener( 'disconnected', function () {

		this.controllerActive = false;
		this.remove( this.children[ 0 ] );

	} );
	workspace.add( controller );

	// controller models
	const controllerModelFactory = new XRControllerModelFactory();
	controllerGrip = renderer.xr.getControllerGrip( 0 );
	controllerGrip.add( controllerModelFactory.createControllerModel( controllerGrip ) );
	workspace.add( controllerGrip );

	onWindowResize();
	window.addEventListener( 'resize', onWindowResize, false );

	// GUI
	const gui = new GUI();
	gui.width = 300;
	gui.add( params, 'displayGrid' );
	gui.open();

}

function buildController( data ) {

	let geometry, material;

	switch ( data.targetRayMode ) {

		case 'tracked-pointer':

			geometry = new BufferGeometry();
			geometry.setAttribute( 'position', new Float32BufferAttribute( [ 0, 0, 0, 0, 0, - 1 ], 3 ) );
			geometry.setAttribute( 'color', new Float32BufferAttribute( [ 0.5, 0.5, 0.5, 0, 0, 0 ], 3 ) );

			material = new LineBasicMaterial( {
				vertexColors: true,
				blending: AdditiveBlending,
				depthWrite: false,
				transparent: true,
			} );

			return new Line( geometry, material );

		case 'gaze':

			geometry = new RingGeometry( 0.02, 0.04, 32 ).translate( 0, 0, - 1 );
			material = new MeshBasicMaterial( { opacity: 0.5, transparent: true } );
			return new Mesh( geometry, material );

	}

}

function onWindowResize() {

	camera.updateProjectionMatrix();
	renderer.setPixelRatio( window.devicePixelRatio );
	renderer.setSize( window.innerWidth, window.innerHeight );

	camera.aspect = window.innerWidth / window.innerHeight;
	camera.updateProjectionMatrix();

}

function handleCamera() {

	// get the XR camera with a combined frustum for culling
	if ( renderer.xr.isPresenting ) {

		if ( xrSession === null ) { // We setup XR camera once

			const xrCamera = renderer.xr.getCamera( camera );

			// remove all cameras so we can use the VR camera instead
			tiles.cameras.forEach( c => tiles.deleteCamera( c ) );
			tiles.setCamera( xrCamera );

			const leftCam = xrCamera.cameras[ 0 ];
			if ( leftCam ) {

				tiles.setResolution( xrCamera, leftCam.viewport.z, leftCam.viewport.w );

			}

			xrSession = renderer.xr.getSession();

		}

	} else {

		// Reset default camera (exiting WebXR session)
		if ( xrSession !== null ) {

			tiles.cameras.forEach( c => tiles.deleteCamera( c ) );

			tiles.setCamera( camera );
			tiles.setResolutionFromRenderer( camera, renderer );

			camera.position.set( 0, 1, 0 );

			xrSession = null;

		}

	}

}

function handleTasks() {

	for ( let t = 0, l = tasks.length; t < l; t ++ ) {

		tasks[ t ]();

	}

	tasks.length = 0;

}

function animate() {

	grid.visible = params.displayGrid;

	// update tiles center
	if ( tiles.getBoundingBox( box ) ) {

		box.getCenter( tiles.group.position );
		tiles.group.position.multiplyScalar( - 1 );

	} else if ( tiles.getBoundingSphere( sphere ) ) {

		tiles.group.position.copy( sphere.center );
		tiles.group.position.multiplyScalar( - 1 );

	}

	// We check for tiles camera setup (default and XR sessions)
	handleCamera();

	// We handle pending tasks
	handleTasks();

	tiles.update();

	if ( controller.controllerActive ) {

		const { ray } = raycaster;
		raycaster.firstHitOnly = true;

		// get the controller ray
		ray.origin
			.copy( controller.position )
			.applyMatrix4( workspace.matrixWorld );
		controller
			.getWorldDirection( ray.direction )
			.multiplyScalar( - 1 );

		const results = raycaster.intersectObject( tiles.group, true );
		if ( results.length ) {

			const hit = results[ 0 ];

			hit.face.normal.transformDirection( tiles.group.matrixWorld );
			intersectRing.position.copy( hit.point );
			intersectRing.quaternion.setFromUnitVectors(
				fwdVector,
				hit.face.normal,
			);
			intersectRing.visible = true;

			// scale ring based on distance
			const scale = workspace.position.distanceTo( intersectRing.position ) * camera.fov / 4000;
			intersectRing.scale.setScalar( scale );

			// only teleport to mostly horizontal surfaces
			if ( hit.face.normal.dot( upVector ) < 0.15 ) {

				intersectRing.visible = false;

			}

		} else {

			intersectRing.visible = false;

		}

	} else {

		intersectRing.visible = false;

	}

	// render primary view
	renderer.render( scene, camera );

}

